    { value:'LCSW',   label:'Clinical Social Worker',         credential:'LCSW'    },
    { value:'LPC',    label:'Professional Counselor',         credential:'LPC'     },
    { value:'LMFT',   label:'Marriage & Family Therapist',    credential:'LMFT'    },
